  CREATE TEMP TABLE _camara_federal_completo_expected (
    slug text NOT NULL PRIMARY KEY,
    expected_rows int NOT NULL,
    old_coverage_id text NOT NULL,
    new_coverage_id text NOT NULL,
    new_coverage_scope text NOT NULL,
    expected_lme_rows int NOT NULL
  ) ON COMMIT DROP;

  INSERT INTO _camara_federal_completo_expected (
    slug,
    expected_rows,
    old_coverage_id,
    new_coverage_id,
    new_coverage_scope,
    expected_lme_rows
  )
  VALUES
    ('eduardo-paes', 339, 'eduardo-paes-camara-autoria-principal-ampliado-parcial-20260507', 'eduardo-paes-camara-completo-autoria-principal-tipos-verificados-1999-2006-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_1999_2006_cutoff_20260511', 0),
    ('acm-neto', 347, 'acm-neto-camara-autoria-principal-ampliado-parcial-20260507', 'acm-neto-camara-completo-autoria-principal-tipos-verificados-2003-2012-cutoff-20260511', 'inventario_completo_camara_autoria_principal_tipos_verificados_2003_2012_cutoff_20260511', 0);

  FOR expected IN SELECT * FROM _camara_federal_completo_expected LOOP
    SELECT count(*)
    INTO missing_before
    FROM _camara_federal_completo_seed seed
    JOIN candidatos c ON c.slug = seed.slug
    LEFT JOIN projetos_lei pl
      ON pl.candidato_id = c.id
     AND pl.proposicao_id_api = seed.proposicao_id_api
    WHERE seed.slug = expected.slug
      AND pl.id IS NULL;

    IF missing_before <> 0 THEN
      RAISE EXCEPTION 'Pre-condicao %: % projetos_lei esperados nao existem no remoto', expected.slug, missing_before;
    END IF;

    SELECT count(*)
    INTO target_after
    FROM _camara_federal_completo_seed seed
    WHERE seed.slug = expected.slug;

    IF target_after <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pre-condicao %: seed tem % rows, esperado %', expected.slug, target_after, expected.expected_rows;
    END IF;
  END LOOP;

  UPDATE projetos_lei pl
  SET
    coverage_id = seed.new_coverage_id,
    coverage_scope = seed.new_coverage_scope,
    metadata = coalesce(pl.metadata, '{}'::jsonb) || seed.metadata_patch
  FROM _camara_federal_completo_seed seed
  JOIN candidatos c ON c.slug = seed.slug
  WHERE pl.candidato_id = c.id
    AND pl.proposicao_id_api = seed.proposicao_id_api;

  FOR expected IN SELECT * FROM _camara_federal_completo_expected LOOP
    SELECT count(*)
    INTO target_after
    FROM projetos_lei pl
    JOIN candidatos c ON c.id = pl.candidato_id
    WHERE c.slug = expected.slug
      AND pl.coverage_id = expected.new_coverage_id
      AND pl.coverage_scope = expected.new_coverage_scope
      AND pl.metadata->>'coverage_status' = 'completo_escopado'
      AND pl.metadata->>'tabela_alvo' = 'projetos_lei'
      AND pl.metadata->>'legislacao_mandato_executivo_mixed' = 'false'
      AND pl.metadata->>'autoria_principal_verificada' = 'true';

    IF target_after <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows completos, esperado %', expected.slug, target_after, expected.expected_rows;
    END IF;

    SELECT count(*)
    INTO old_after
    FROM projetos_lei pl
    JOIN candidatos c ON c.id = pl.candidato_id
    WHERE c.slug = expected.slug
      AND pl.coverage_id = expected.old_coverage_id;

    IF old_after <> 0 THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows ficaram no coverage parcial antigo', expected.slug, old_after;
    END IF;

    SELECT count(*)
    INTO lme_after
    FROM legislacao_mandato_executivo lme
    JOIN candidatos c ON c.id = lme.candidato_id
    WHERE c.slug = expected.slug;

    IF lme_after <> expected.expected_lme_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: LME mudou de % para %', expected.slug, expected.expected_lme_rows, lme_after;
    END IF;
  END LOOP;
END $$;
